55	const PROCESSING_FEE = 5;
56	const BLOCK_SIZE = 3;
57	const COMPONENT_BLOCK_PRICE = 60;
58	const CURSED_SURCHARGE_RATE = 0.5;
59	const FIRST_INSURANCE_RATE = 0.1;
60	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
61	  sword: 100,
62	  amulet: 60,
63	  staff: 80,
64	  potion: 40,
65	  rune: 25,
66	  moonstone: 25,
67	};
68	
69	const basePremium = (item: Item): number =>
70	  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
71	
72	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
73	
74	const groupByType = (items: Item[]): Map<string, Item[]> => {
75	  const groups = new Map<string, Item[]>();
76	  for (const item of items) {
77	    const existing = groups.get(item.type) ?? [];
78	    existing.push(item);
79	    groups.set(item.type, existing);
80	  }
81	  return groups;
82	};
83	
84	const sumBasePremiums = (items: Item[]): number =>
85	  items.reduce((sum, item) => sum + basePremium(item), 0);
86	
87	const groupTotal = (type: string, group: Item[]): number => {
88	  if (group.length === BLOCK_SIZE && COMPONENT_TYPES.has(type)) {
89	    return COMPONENT_BLOCK_PRICE;
90	  }
91	  return sumBasePremiums(group);
92	};
93	
94	const componentsTotal = (items: Item[]): number => {
95	  let total = 0;
96	  for (const [type, group] of groupByType(items)) {
97	    total += groupTotal(type, group);
98	  }
99	  return total;
100	};
101	
102	const cursedSurcharge = (items: Item[]): number =>
103	  items.reduce(
104	    (sum, item) =>
105	      sum + (item.cursed ? basePremium(item) * CURSED_SURCHARGE_RATE : 0),
106	    0,
107	  );
108	
109	const quotePremium = (items: Item[]): number => {
110	  const policyBase = componentsTotal(items);
111	  const surcharges = cursedSurcharge(items) + policyBase * FIRST_INSURANCE_RATE;
112	  return Math.ceil(policyBase + surcharges) + PROCESSING_FEE;
113	};
114	
115	export const processScenario = (scenario: Scenario): ScenarioOutput => {
116	  const step = scenario.steps[0] as QuoteStep;
117	  return { results: [{ premium: quotePremium(step.items) }] };
118	};
